    44→  async startRecording(url: string, sessionId: string): Promise<void> {
    45→    if (this.isRecording) {
    46→      throw new Error('Already recording');
    47→    }
    48→
    49→    // Ensure screenshot directory exists
    50→    if (!fs.existsSync(this.screenshotDir)) {
    51→      fs.mkdirSync(this.screenshotDir, { recursive: true });
    52→    }
    53→
    54→    this.lastCompletedSession = null; // Clear any previous completed session
    55→    this.session = {
    56→      id: sessionId,
    57→      url,
    58→      startedAt: new Date(),
    59→      events: [],
    60→      generatedCode: '',
    61→    };
    62→
    63→    try {
    64→      this.browser = await chromium.launch({
    65→        headless: false,
    66→        args: ['--start-maximized'],
    67→      });
    68→
    69→      this.context = await this.browser.newContext({
    70→        viewport: { width: 1280, height: 720 },
    71→        ignoreHTTPSErrors: true, // Ignore SSL errors for local dev
    72→      });
    73→
    74→      this.page = await this.context.newPage();
    75→
    76→      // Setup event listeners BEFORE navigation (must await these)
    77→      await this.setupEventListeners();
    78→
    79→      // Navigate to initial URL
    80→      await this.page.goto(url, { waitUntil: 'domcontentloaded' });
    81→      this.addEvent('navigation', { url });
    82→
    83→      this.isRecording = true;
    84→      this.emit('started', { sessionId, url });
    85→    } catch (error) {
    86→      await this.cleanup();
    87→      throw error;
    88→    }
    89→  }
