    91→  private async setupEventListeners(): Promise<void> {
    92→    if (!this.page) return;
    93→
    94→    // Track navigation
    95→    this.page.on('framenavigated', (frame) => {
    96→      if (frame === this.page?.mainFrame()) {
    97→        this.addEvent('navigation', { url: frame.url() });
    98→      }
    99→    });
   100→
   101→    // Track page close to stop recording
   102→    this.page.on('close', () => {
   103→      if (this.isRecording) {
   104→        this.stopRecording().catch(() => {});
   105→      }
   106→    });
   107→
   108→    // Expose function to track interactions from the page - MUST await
   109→    await this.page.exposeFunction('__recordAction', (action: string, selectors: ActionSelector[], value?: string) => {
   110→      // Store both multi-selector array and legacy single selector for backwards compatibility
   111→      const primarySelector = selectors[0]?.value || '';
   112→      this.addEvent('action', { action, selector: primarySelector, selectors, value });
   113→    });
   114→
   115→    // Inject interaction tracking script - MUST await
   116→    await this.page.addInitScript(() => {
   117→      // Type definition for selectors captured in browser context
   118→      interface BrowserActionSelector {
   119→        type: string;
   120→        value: string;
   121→      }
   122→
   123→      document.addEventListener('click', (e) => {
   124→        const target = e.target as HTMLElement;
   125→        const selectors = generateAllSelectors(target);
   126→        // @ts-ignore
   127→        window.__recordAction?.('click', selectors);
   128→      }, true);
   129→
   130→      document.addEventListener('input', (e) => {
   131→        const target = e.target as HTMLInputElement;
   132→        const selectors = generateAllSelectors(target);
   133→        // @ts-ignore
   134→        window.__recordAction?.('fill', selectors, target.value);
   135→      }, true);
   136→
   137→      document.addEventListener('change', (e) => {
   138→        const target = e.target as HTMLSelectElement;
   139→        if (target.tagName === 'SELECT') {
   140→          const selectors = generateAllSelectors(target);
   141→          // @ts-ignore
   142→          window.__recordAction?.('selectOption', selectors, target.value);
   143→        }
   144→      }, true);
   145→
   146→      // Generate ALL available selectors for an element
   147→      function generateAllSelectors(element: HTMLElement): BrowserActionSelector[] {
   148→        const selectors: BrowserActionSelector[] = [];
   149→
   150→        // 1. data-testid (highest priority)
   151→        if (element.dataset.testid) {
   152→          selectors.push({
   153→            type: 'data-testid',
   154→            value: `[data-testid="${element.dataset.testid}"]`,
   155→          });
   156→        }
   157→
   158→        // 2. ID
   159→        if (element.id) {
   160→          selectors.push({
   161→            type: 'id',
   162→            value: `#${element.id}`,
   163→          });
   164→        }
   165→
   166→        // 3. Role + name (ARIA)
   167→        const role = element.getAttribute('role') || getImplicitRole(element);
   168→        const accessibleName = element.getAttribute('aria-label') ||
   169→          element.getAttribute('title') ||
   170→          element.textContent?.trim().slice(0, 30);
   171→        if (role && accessibleName) {
   172→          selectors.push({
   173→            type: 'role-name',
   174→            value: `role=${role}[name="${accessibleName}"]`,
   175→          });
   176→        }
   177→
   178→        // 4. aria-label
   179→        const ariaLabel = element.getAttribute('aria-label');
   180→        if (ariaLabel) {
   181→          selectors.push({
   182→            type: 'aria-label',
   183→            value: `[aria-label="${ariaLabel}"]`,
   184→          });
   185→        }
   186→
   187→        // 5. Text content (for buttons/links)
   188→        if (element.tagName === 'BUTTON' || element.tagName === 'A' ||
   189→            element.getAttribute('role') === 'button') {
   190→          const text = element.textContent?.trim().slice(0, 30);
   191→          if (text) {
   192→            selectors.push({
   193→              type: 'text',
   194→              value: `text="${text}"`,
   195→            });
   196→          }
   197→        }
   198→
   199→        // 6. CSS path fallback
   200→        const cssPath = generateCssPath(element);
   201→        if (cssPath) {
   202→          selectors.push({
   203→            type: 'css-path',
   204→            value: cssPath,
   205→          });
   206→        }
   207→
   208→        return selectors;
   209→      }
   210→
   211→      // Get implicit ARIA role for common elements
   212→      function getImplicitRole(element: HTMLElement): string | null {
   213→        const tagRoles: Record<string, string> = {
   214→          'BUTTON': 'button',
   215→          'A': 'link',
   216→          'INPUT': element.getAttribute('type') === 'checkbox' ? 'checkbox' :
   217→                   element.getAttribute('type') === 'radio' ? 'radio' :
   218→                   element.getAttribute('type') === 'submit' ? 'button' : 'textbox',
   219→          'SELECT': 'combobox',
   220→          'TEXTAREA': 'textbox',
   221→          'IMG': 'img',
   222→          'NAV': 'navigation',
   223→          'MAIN': 'main',
   224→          'HEADER': 'banner',
   225→          'FOOTER': 'contentinfo',
   226→        };
   227→        return tagRoles[element.tagName] || null;
   228→      }
   229→
   230→      // Generate CSS path selector
   231→      function generateCssPath(element: HTMLElement): string {
   232→        const path: string[] = [];
   233→        let current: HTMLElement | null = element;
   234→        while (current && current !== document.body) {
   235→          let selector = current.tagName.toLowerCase();
   236→          if (current.className) {
   237→            const classes = current.className.split(' ')
   238→              .filter(c => c && !c.includes(':') && !c.startsWith('_'))
   239→              .slice(0, 2);
   240→            if (classes.length > 0) {
   241→              selector += '.' + classes.join('.');
   242→            }
   243→          }
   244→          path.unshift(selector);
   245→          current = current.parentElement;
   246→        }
   247→        return path.slice(-3).join(' > ');
   248→      }
   249→    });
   250→  }
