     9→export async function getGitInfo(): Promise<GitInfo> {
    10→  try {
    11→    const branch = execSync('git rev-parse --abbrev-ref HEAD', { encoding: 'utf-8' }).trim();
    12→    const commit = execSync('git rev-parse --short HEAD', { encoding: 'utf-8' }).trim();
    13→    const status = execSync('git status --porcelain', { encoding: 'utf-8' }).trim();
    14→
    15→    return {
    16→      branch,
    17→      commit,
    18→      isClean: status === '',
    19→    };
    20→  } catch {
    21→    return {
    22→      branch: 'unknown',
    23→      commit: 'unknown',
    24→      isClean: true,
    25→    };
    26→  }
    27→}
