     7→export async function fetchAndSyncRepos(): Promise<{ success: boolean; count: number }> {
     8→  const account = await queries.getGithubAccount();
     9→  if (!account) {
    10→    return { success: false, count: 0 };
    11→  }
    12→
    13→  const ghRepos = await getUserRepos(account.accessToken);
    14→  if (!ghRepos.length) {
    15→    return { success: false, count: 0 };
    16→  }
    17→
    18→  // Upsert repos
    19→  for (const repo of ghRepos) {
    20→    const existing = await queries.getRepositoryByGithubId(repo.id);
    21→    if (existing) {
    22→      await queries.updateRepository(existing.id, {
    23→        owner: repo.owner.login,
    24→        name: repo.name,
    25→        fullName: repo.full_name,
    26→        defaultBranch: repo.default_branch,
    27→      });
    28→    } else {
    29→      await queries.createRepository({
    30→        githubRepoId: repo.id,
    31→        owner: repo.owner.login,
    32→        name: repo.name,
    33→        fullName: repo.full_name,
    34→        defaultBranch: repo.default_branch,
    35→      });
    36→    }
    37→  }
    38→
    39→  revalidatePath('/');
    40→  revalidatePath('/repo');
    41→  revalidatePath('/settings');
    42→  return { success: true, count: ghRepos.length };
    43→}
