     8→
     9→export async function startRouteScan(repositoryId: string, scanPath?: string) {
    10→  // Default to current working directory if no path provided
    11→  const pathToScan = scanPath || process.cwd();
    12→
    13→  // Delete existing routes and scan status for this repo
    14→  await queries.deleteRoutesByRepo(repositoryId);
    15→  await queries.deleteScanStatus(repositoryId);
    16→
    17→  // Create initial scan status
    18→  const status = await queries.createScanStatus({
    19→    repositoryId,
    20→    status: 'scanning',
    21→    progress: 0,
    22→    routesFound: 0,
    23→    startedAt: new Date(),
    24→  });
    25→
    26→  try {
    27→    const scanner = new RouteScanner(pathToScan, async (progress) => {
    28→      // Update scan progress
    29→      await queries.updateScanStatus(status.id, {
    30→        progress: progress.progress,
    31→        routesFound: progress.routesFound,
    32→      });
    33→    });
    34→
    35→    const result = await scanner.scan();
    36→
    37→    // Save discovered routes
    38→    const routesToCreate = result.routes.map((r: RouteInfo) => ({
    39→      repositoryId,
    40→      path: r.path,
    41→      type: r.type,
    42→      filePath: r.filePath,
    43→      framework: r.framework,
    44→      routerType: r.routerType,
    45→      hasTest: false,
    46→      scannedAt: new Date(),
    47→    }));
    48→
    49→    await queries.createRoutes(routesToCreate);
    50→
    51→    // Update scan status to completed
    52→    await queries.updateScanStatus(status.id, {
    53→      status: 'completed',
    54→      progress: 100,
    55→      routesFound: result.routes.length,
    56→      framework: result.framework,
    57→      completedAt: new Date(),
    58→    });
    59→
    60→    revalidatePath('/repo');
    61→    revalidatePath('/tests');
    62→    revalidatePath('/');
    63→
    64→    return {
    65→      success: true,
    66→      routesFound: result.routes.length,
    67→      framework: result.framework,
    68→    };
    69→  } catch (error) {
    70→    await queries.updateScanStatus(status.id, {
    71→      status: 'error',
    72→      errorMessage: error instanceof Error ? error.message : 'Unknown error',
    73→      completedAt: new Date(),
    74→    });
    75→
    76→    return {
    77→      success: false,
    78→      error: error instanceof Error ? error.message : 'Unknown error',
    79→    };
    80→  }
    81→}
    82→
