    95→export async function addRoutesAsFunctionalAreas(repositoryId: string, routeIds: string[]) {
    96→  const routesToAdd = await queries.getRoutesByIds(routeIds);
    97→  let areasCreated = 0;
    98→
    99→  for (const route of routesToAdd) {
   100→    // Create functional area with route path as name
   101→    const area = await queries.createFunctionalArea({
   102→      repositoryId,
   103→      name: route.path,
   104→      description: `Auto-generated area for route ${route.path}`,
   105→    });
   106→
   107→    // Link route to area
   108→    await queries.linkRouteToFunctionalArea(route.id, area.id);
   109→    areasCreated++;
   110→  }
   111→
   112→  revalidatePath('/tests');
   113→  revalidatePath('/');
   114→
   115→  return { areasCreated };
   116→}
   117→
   118→export async function generateBasicTests(repositoryId: string, routeIds: string[], baseUrl: string) {
   119→  const routesToTest = await queries.getRoutesByIds(routeIds);
   120→  let testsCreated = 0;
   121→
   122→  for (const route of routesToTest) {
   123→    // Ensure route has a functional area
   124→    let functionalAreaId = route.functionalAreaId;
   125→
   126→    if (!functionalAreaId) {
   127→      const area = await queries.createFunctionalArea({
   128→        repositoryId,
   129→        name: route.path,
   130→        description: `Auto-generated area for route ${route.path}`,
   131→      });
   132→      functionalAreaId = area.id;
   133→      await queries.linkRouteToFunctionalArea(route.id, area.id);
   134→    }
   135→
   136→    // Generate smoke test code
   137→    const testCode = generateSmokeTestCode(
   138→      {
   139→        path: route.path,
   140→        type: route.type as 'static' | 'dynamic',
   141→        routerType: route.routerType as 'hash' | 'browser' | undefined,
   142→      },
   143→      baseUrl
   144→    );
   145→
   146→    // Create test
   147→    await queries.createTest({
   148→      repositoryId,
   149→      functionalAreaId,
   150→      name: `Smoke test: ${route.path}`,
   151→      pathType: 'happy',
   152→      code: testCode,
   153→      targetUrl: route.routerType === 'hash' ? `${baseUrl}/#${route.path}` : `${baseUrl}${route.path}`,
   154→    });
   155→
   156→    // Mark route as having a test
   157→    await queries.updateRoute(route.id, { hasTest: true });
   158→    testsCreated++;
   159→  }
   160→
   161→  revalidatePath('/tests');
   162→  revalidatePath('/');
   163→
   164→  return { testsCreated };
   165→}
