     8→export async function startRecording(url: string): Promise<{ sessionId?: string; error?: string }> {
     9→  const recorder = getRecorder();
    10→
    11→  if (recorder.isActive()) {
    12→    return { error: 'Recording already in progress' };
    13→  }
    14→
    15→  // Validate URL format
    16→  try {
    17→    new URL(url);
    18→  } catch {
    19→    return { error: 'Invalid URL format. Please enter a valid URL (e.g., https://example.com)' };
    20→  }
    21→
    22→  const sessionId = uuid();
    23→
    24→  try {
    25→    await recorder.startRecording(url, sessionId);
    26→    return { sessionId };
    27→  } catch (err) {
    28→    const message = err instanceof Error ? err.message : 'Failed to start recording';
    29→
    30→    // Parse common Playwright errors
    31→    if (message.includes('ERR_NAME_NOT_RESOLVED')) {
    32→      return { error: `Could not resolve hostname. Please check the URL: ${url}` };
    33→    }
